using System.ComponentModel;
using System.Net.Http.Json;
using System.Text;
using System.Text.Json.Serialization;
using Microsoft.Agents.AI;
using Microsoft.Agents.AI.Abstractions;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.Logging;
using OpenAI;

// --- Configuration -----------------------------------------------------------

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable.");

// Pin to a specific dated model version to reduce behavioral drift.
var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
    ?? "gpt-4o-mini-2024-07-18";

// --- Chat client pipeline ----------------------------------------------------

using var loggerFactory = LoggerFactory.Create(builder => builder
    .AddConsole()
    .SetMinimumLevel(LogLevel.Warning));

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Tools -------------------------------------------------------------------

var notebook = new ResearchNotebook();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

var searchTool = new WebSearchTool(httpClient);

var tools = new List<AITool>
{
    AIFunctionFactory.Create(searchTool.SearchAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// --- Agent -------------------------------------------------------------------

const string instructions = """
    You are a research agent. Thoroughly research the topic the user provides.

    Process:
    1. Break the topic into 2-3 focused search queries.
    2. Use web_search for each query.
    3. Use add_note to save every key finding as you go.
    4. After gathering enough information, call get_notes to review your findings.
    5. Write a comprehensive summary with key points and source URLs.

    Be thorough but concise. Always cite sources.
    """;

var agent = new ChatClientAgent(
    chatClient,
    instructions,
    name: "ResearchAgent",
    description: "Researches topics using web search and note-taking",
    tools: tools,
    loggerFactory: loggerFactory,
    services: null);

// --- Run ---------------------------------------------------------------------

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.Error.WriteLine("No topic provided.");
    return;
}

Console.WriteLine($"\n  Researching: {topic}\n");

var session = new AgentSession();

var response = await agent.RunAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    options: null,
    cancellationToken: CancellationToken.None);

Console.WriteLine(new string('═', 60));
Console.WriteLine(" RESEARCH SUMMARY");
Console.WriteLine(new string('═', 60));

foreach (var message in response.Messages)
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
    {
        Console.WriteLine(message.Text);
    }
}

if (notebook.Notes.Count > 0)
{
    Console.WriteLine();
    Console.WriteLine(new string('─', 60));
    Console.WriteLine($" {notebook.Notes.Count} note(s) saved during research:");
    foreach (var note in notebook.Notes)
    {
        Console.WriteLine($"   • {note.Title}");
    }
}

// =============================================================================
// Tool implementations
// =============================================================================

/// <summary>Searches the web using the DuckDuckGo Instant Answer API.</summary>
sealed class WebSearchTool(HttpClient httpClient)
{
    [Description("Search the web for information on a query. Returns result snippets and source URLs.")]
    public async Task<string> SearchAsync(
        [Description("The search query")] string query,
        CancellationToken cancellationToken = default)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            var ddg = await httpClient.GetFromJsonAsync<DdgResponse>(url, cancellationToken);

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for: \"{query}\"\n");

            if (!string.IsNullOrWhiteSpace(ddg?.AbstractText))
            {
                sb.AppendLine($"Overview: {ddg.AbstractText}");
                if (!string.IsNullOrWhiteSpace(ddg.AbstractURL))
                    sb.AppendLine($"Source: {ddg.AbstractURL}");
                sb.AppendLine();
            }

            if (ddg?.RelatedTopics is { Count: > 0 })
            {
                sb.AppendLine("Related findings:");
                foreach (var topic in ddg.RelatedTopics.Take(8))
                {
                    if (!string.IsNullOrWhiteSpace(topic.Text))
                    {
                        sb.AppendLine($"  - {topic.Text}");
                        if (!string.IsNullOrWhiteSpace(topic.FirstURL))
                            sb.AppendLine($"    URL: {topic.FirstURL}");
                    }
                }
            }

            var result = sb.ToString().Trim();
            return result.Length > 50
                ? result
                : $"No detailed results found for \"{query}\". Try rephrasing or using more specific terms.";
        }
        catch (Exception ex)
        {
            return $"Search failed ({ex.GetType().Name}): {ex.Message}. Try a different query.";
        }
    }
}

sealed class DdgResponse
{
    [JsonPropertyName("AbstractText")]
    public string? AbstractText { get; set; }

    [JsonPropertyName("AbstractURL")]
    public string? AbstractURL { get; set; }

    [JsonPropertyName("RelatedTopics")]
    public List<DdgTopic>? RelatedTopics { get; set; }
}

sealed class DdgTopic
{
    [JsonPropertyName("Text")]
    public string? Text { get; set; }

    [JsonPropertyName("FirstURL")]
    public string? FirstURL { get; set; }
}

/// <summary>In-memory notebook for storing research findings.</summary>
sealed class ResearchNotebook
{
    public List<Note> Notes { get; } = [];

    [Description("Save a research note. Use this to record key findings during research.")]
    public string AddNote(
        [Description("Short descriptive title")] string title,
        [Description("The finding or information to save")] string content)
    {
        Notes.Add(new Note(title, content));
        return $"Note #{Notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieve all saved research notes to review before writing the summary.")]
    public string GetNotes()
    {
        if (Notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"Research Notes ({Notes.Count}):\n");
        for (var i = 0; i < Notes.Count; i++)
        {
            sb.AppendLine($"  [{i + 1}] {Notes[i].Title}");
            sb.AppendLine($"      {Notes[i].Content}");
            sb.AppendLine();
        }
        return sb.ToString();
    }
}

record Note(string Title, string Content);

